// src/pages/RegisterManageSub2Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../Dashboard.css';
import './FormPage.css';

function FarmListPage() {
  const [farms, setFarms] = useState([]);
  const [filter, setFilter] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(response.data);
      } catch (error) {
        console.error('❌ Lỗi khi lấy danh sách cơ sở nuôi:', error);
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Không thể tải danh sách cơ sở nuôi. Vui lòng thử lại hoặc kiểm tra quyền truy cập.');
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
      }
    };

    if (token) {
      fetchFarms();
    } else {
      navigate('/'); // Chuyển hướng nếu không có token
    }
  }, [token, navigate]);

  const handleDelete = async (id) => {
    // Thay thế window.confirm bằng một modal xác nhận tùy chỉnh
    if (window.confirm('Bạn có chắc chắn muốn xoá?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(farms.filter(f => f._id !== id));
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Xoá thành công!');
      } catch (error) {
        console.error('Lỗi khi xoá:', error);
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Xoá thất bại. Vui lòng thử lại hoặc kiểm tra quyền truy cập.');
      }
    }
  };

  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Chuyển hướng đến trang chỉnh sửa
  };

  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Chuyển hướng đến trang chi tiết farm
  };

  // Cập nhật logic lọc để bao gồm các trường mới nếu cần
  const filteredFarms = farms.filter(f =>
    (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) || // Sử dụng tinhThanhPho mới
    (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) || // Sử dụng tenNguoiDaiDien mới
    (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) // Tìm kiếm theo địa chỉ cơ sở
  );

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <input
        type="text"
        placeholder="🔍 Tìm kiếm theo tỉnh, tên cơ sở, người đại diện, hoặc địa chỉ..."
        value={filter}
        onChange={e => setFilter(e.target.value)}
        style={{ marginBottom: 12, padding: 8, width: '50%' }}
      />

      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              <th>Tên cơ sở</th>
              <th>Tỉnh (TP)</th> {/* Cập nhật tiêu đề cột */}
              <th>Xã (Phường)</th> {/* Thêm cột mới */}
              <th>Địa chỉ cơ sở</th> {/* Cập nhật tiêu đề cột */}
              <th>Người đại diện</th> {/* Cập nhật tiêu đề cột */}
              <th>SĐT Người đại diện</th> {/* Thêm cột mới */}
              <th>Email Người đại diện</th> {/* Thêm cột mới */}
              <th>Loại hình cơ sở</th> {/* Thêm cột mới */}
              <th>Ngày thành lập</th> {/* Thêm cột mới */}
              <th>Số GPKD</th> {/* Thêm cột mới */}
              <th>🛠️</th>
            </tr>
          </thead>
          <tbody>
            {filteredFarms.map((f, i) => (
              <tr key={f._id || i}>
                <td>{f.tenCoSo}</td>
                <td>{f.tinhThanhPho}</td> {/* Hiển thị trường mới */}
                <td>{f.xaPhuong}</td> {/* Hiển thị trường mới */}
                <td>{f.diaChiCoSo}</td> {/* Hiển thị trường mới */}
                <td>{f.tenNguoiDaiDien}</td> {/* Hiển thị trường mới */}
                <td>{f.soDienThoaiNguoiDaiDien}</td> {/* Hiển thị trường mới */}
                <td>{f.emailNguoiDaiDien}</td> {/* Hiển thị trường mới */}
                <td>{f.loaiHinhCoSo}</td> {/* Hiển thị trường mới */}
                <td>{f.ngayThanhLap ? new Date(f.ngayThanhLap).toLocaleDateString() : ''}</td> {/* Định dạng ngày */}
                <td>{f.giayPhepKinhDoanh}</td> {/* Hiển thị trường mới */}
                <td>
                  <button onClick={() => handleView(f._id)} className="action-button view-button">Sổ nuôi</button>{' '}
                  <button onClick={() => handleEdit(f._id)} className="action-button edit-button">✏️</button>{' '}
                  <button onClick={() => handleDelete(f._id)} className="action-button delete-button">🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default FarmListPage;
